def _index_by(items, key):
    return {item[key]: item for item in items}


IDX_CATEGORY_BY_ID = _index_by(DATA["categories"], "id")
IDX_CATEGORY_BY_SLUG = _index_by(DATA["categories"], "slug")
IDX_PRODUCT_BY_ID = _index_by(DATA["products"], "id")
IDX_PRODUCT_BY_SKU = _index_by(DATA["products"], "sku")
IDX_USER_BY_ID = _index_by(DATA["users"], "id")


def _filter_products(
    category_id=None,
    category_slug=None,
    search=None,
    min_price=None,
    max_price=None,
    in_stock=None,
    tag=None,
    limit=None,
    offset=None,
):
    products = DATA["products"][:]

    if category_slug is not None:
        cat = IDX_CATEGORY_BY_SLUG.get(category_slug)
        if not cat:
            products = []
        else:
            category_id = cat["id"]

    if category_id is not None:
        products = [p for p in products if p["category_id"] == category_id]

    if search:
        s = search.lower().strip()
        products = [
            p for p in products
            if s in p["name"].lower() or s in (p.get("description") or "").lower() or s in p.get("sku", "").lower()
        ]

    if min_price is not None:
        products = [p for p in products if p["price"] >= min_price]

    if max_price is not None:
        products = [p for p in products if p["price"] <= max_price]

    if in_stock is not None:
        products = [p for p in products if p["in_stock"] == in_stock]

    if tag:
        t = tag.lower().strip()
        products = [p for p in products if any(t == (x or "").lower() for x in p.get("tags", []))]

    if offset:
        products = products[offset:]

    if limit is not None:
        products = products[:limit]

    return products


def _reviews_for_product(product_id, limit=None, offset=None, min_rating=None, user_id=None):
    reviews = [r for r in DATA["reviews"] if r["product_id"] == product_id]
    if min_rating is not None:
        reviews = [r for r in reviews if r["rating"] >= min_rating]
    if user_id is not None:
        reviews = [r for r in reviews if r["user_id"] == user_id]
    reviews.sort(key=lambda r: r["created_at"], reverse=True)
    if offset:
        reviews = reviews[offset:]
    if limit is not None:
        reviews = reviews[:limit]
    return reviews


class UserType(ObjectType):
    id = Int(required=True)
    name = String(required=True)


class CategoryType(ObjectType):
    id = Int(required=True)
    slug = String(required=True)
    name = String(required=True)

    products = List(
        lambda: ProductType,
        search=Argument(String),
        min_price=Argument(Float),
        max_price=Argument(Float),
        in_stock=Argument(Boolean),
        tag=Argument(String),
        limit=Argument(Int),
        offset=Argument(Int),
    )

    def resolve_products(self, info, **kwargs):
        return _filter_products(category_id=self["id"], **kwargs)


class ReviewType(ObjectType):
    id = Int(required=True)
    product_id = Int(required=True)
    user_id = Int(required=True)
    rating = Int(required=True)
    title = String(required=True)
